package be.schaubroeck.lpb.rkm.rekenmotor.rsz.dmfa;

import be.schaubroeck.lpb.rkm.rekenmotor.LoonElement;
import be.schaubroeck.lpb.rkm.rekenmotor.RekenTijd;
import be.schaubroeck.lpb.rkm.rekenmotor.RkmCoreHrConfiguratie;
import be.schaubroeck.lpb.rkm.rekenmotor.keys.RekenBrutoKey;
import be.schaubroeck.lpb.rkm.rekenmotor.keys.RekenRszKey;
import be.schaubroeck.lpb.rkm.rekenmotor.util.ConstantManager;
import be.schaubroeck.lpb.rkm.rekenmotor.util.LoonElementManager;
import be.schaubroeck.lpb.rkm.rekenmotor.util.RkmCoreHrConfiguratieManager;
import be.schaubroeck.lpb.tools.AardKodeExtensie;
import be.schaubroeck.lpb.tools.Constant;
import be.schaubroeck.lpb.tools.Money;
import be.schaubroeck.lpb.tools.Opdracht;
import be.schaubroeck.lpb.tools.Persoon;
import be.schaubroeck.lpb.tools.enumtypes.Hoedanigheid;
import be.schaubroeck.lpb.tools.enumtypes.Konstanten;
import be.schaubroeck.lpb.tools.enumtypes.TerugbetalingRszNbMandataris;
import lombok.AllArgsConstructor;
import lombok.Builder;
import org.joda.time.LocalDate;

import java.util.Collection;

@AllArgsConstructor
@Builder
public class BerekenTerugbetalingSocialeBijdragen {

    private static final LocalDate START_TERUGBETALING_SOCIALE_BIJDRAGEN = new LocalDate(2022, 1, 1);
    private static final Integer AKE_CODE = 1100;
    private static final Integer AKE_EXT = 5;

    private final ConstantManager constantManager;
    private final RkmCoreHrConfiguratieManager rkmCoreHrConfiguratieManager;
    private final LoonElementManager elementManager;
    private final RekenTijd rekenTijd;

    public void bereken(Persoon persoon) {
        if (isActief()) {
            for (Opdracht opdracht : persoon.getOpdrachten()) {
                bereken(opdracht);
            }
        }
    }

    private void bereken(Opdracht opdracht) {
        TerugbetalingRszNbMandataris type = bepaalTypeTerugbetaling(opdracht);
        LoonElement elementTerugbetalingRsz = getLoonElementTerugbetalingRsz(opdracht);
        if (opdracht.getHoedanigheid() == Hoedanigheid.MANDATARISSEN_NIET_BESCHERMD && type != TerugbetalingRszNbMandataris.NVT && elementTerugbetalingRsz != null) {
            Collection<LoonElement> elementen = elementManager.getOpdrachtsElementen(opdracht);
            Money terugTeBetalen = elementen.stream().map(x -> getSocialeBijdragenInAanmerking(x, type)).reduce(Money.ZERO, Money::add);
            elementTerugbetalingRsz.putProperty(RekenBrutoKey.BRUTO_MAANDLOON_KEY, terugTeBetalen);
        }
    }

    private Money getSocialeBijdragenInAanmerking(LoonElement element, TerugbetalingRszNbMandataris type) {
        Money terugTeBetalen = element.getPropertyMoney(RekenRszKey.BIJDRAGE_RSZ_KEY);
        terugTeBetalen = terugTeBetalen.add(element.getPropertyMoney(RekenRszKey.BIJDRAGE_DUBBEL_VAKANTIEGELD_MANDATARIS_KEY));
        terugTeBetalen = terugTeBetalen.add(element.getPropertyMoney(RekenRszKey.BIJDRAGE_PENSIOEN_MANDATARIS_KEY));
        if (type == TerugbetalingRszNbMandataris.RSZ_EN_BIJZONDERE_BIJDRAGE) {
            terugTeBetalen = terugTeBetalen.add(element.getPropertyMoney(RekenRszKey.BIJZONDERE_BIJDRAGE_KEY));
        }
        return terugTeBetalen;
    }

    private LoonElement getLoonElementTerugbetalingRsz(Opdracht opdracht) {
        return elementManager.getOpdrachtsElementen(opdracht).stream()
                .filter(BerekenTerugbetalingSocialeBijdragen::isLoonElementTerugbetalingRsz)
                .findFirst().orElse(null);
    }

    public static boolean isLoonElementTerugbetalingRsz(LoonElement element) {
        AardKodeExtensie ake = element.getAardKodeExtensie();
        return isLoonElementTerugbetalingRsz(ake);
    }

    public static boolean isLoonElementTerugbetalingRsz(AardKodeExtensie ake) {
        return ake.getCode().equals(AKE_CODE) && ake.getExtensie().equals(AKE_EXT);
    }

    private TerugbetalingRszNbMandataris bepaalTypeTerugbetaling(Opdracht opdracht) {
        RkmCoreHrConfiguratie rkmCoreHrConfiguratie = rkmCoreHrConfiguratieManager.getRkmCoreHrConfiguratie(opdracht, rekenTijd);
        if (rkmCoreHrConfiguratie != null && rkmCoreHrConfiguratie.getTerugbetalingRszNbMandataris() != null) {
            return rkmCoreHrConfiguratie.getTerugbetalingRszNbMandataris();
        } else {
            Constant constante = constantManager.getActualConstant(Konstanten.CST_TERUGBETALING_NB_MANDATARIS, rekenTijd);
            if (constante != null) {
                return TerugbetalingRszNbMandataris.getByCode(constante.getInteger());
            } else {
                return TerugbetalingRszNbMandataris.NVT;
            }
        }
    }

    private boolean isActief() {
        return !rekenTijd.beginDatum.isBefore(START_TERUGBETALING_SOCIALE_BIJDRAGEN);
    }
}
